module rv32i_min_core #(
    parameter integer XLEN = 32,
    parameter integer RESET_PC = 0,
    parameter integer INST_ALIGN = 4
) (
    input  logic                 clk,
    input  logic                 rst_n,
    output logic [XLEN-1:0]      i_addr,
    input  logic [XLEN-1:0]      i_rdata,
    output logic                 i_valid,
    input  logic                 alu_result,
    input  logic                 branch_imm,
    input  logic                 branch_taken,
    input  logic                 illegal_shamt,
    input  logic                 imm,
    input  logic                 is_ebreak,
    input  logic                 is_ecall,
    input  logic                 is_jalr,
    input  logic                 is_store,
    input  logic                 load_data_ext,
    input  logic                 misaligned_access,
    input  logic                 rs1,
    output logic [XLEN-1:0]      d_addr,
    output logic [XLEN-1:0]      d_wdata,
    input  logic [XLEN-1:0]      d_rdata,
    output logic                 d_we,
    output logic [3:0]           d_be,
    output logic                 d_valid,
    output logic                 excpt_o
);

    localparam [1:0] ST_RESET = 2'd0,
                     ST_RUN   = 2'd1,
                     ST_FENCE = 2'd2;

    localparam [6:0] OPCODE_LOAD   = 7'b0000011,
                     OPCODE_STORE  = 7'b0100011,
                     OPCODE_BRANCH = 7'b1100011,
                     OPCODE_JALR   = 7'b1100111,
                     OPCODE_JAL    = 7'b1101111,
                     OPCODE_SYSTEM = 7'b1110011,
                     OPCODE_MISC   = 7'b0001111;

    logic [1:0] state;

    logic [XLEN-1:0] pc;
    logic [XLEN-1:0] next_pc;

    logic            if_valid;
    logic [XLEN-1:0] if_pc;
    logic [XLEN-1:0] if_instr;

    logic            ex_valid;
    logic [XLEN-1:0] ex_pc;
    logic [XLEN-1:0] ex_instr;

    logic            wb_valid;
    logic [XLEN-1:0] wb_pc;
    logic [XLEN-1:0] wb_instr;

    logic [4:0]      rs1_idx;
    logic [4:0]      rs2_idx;
    logic [4:0]      rd_idx;
    logic [6:0]      decoded_opcode;
    logic [2:0]      funct3;
    logic [6:0]      funct7;

    logic [XLEN-1:0] regfile [0:31];

    logic [XLEN-1:0] rs1_data;
    logic [XLEN-1:0] rs2_data;

    logic [XLEN-1:0] imm_i;
    logic [XLEN-1:0] imm_s;
    logic [XLEN-1:0] imm_b;
    logic [XLEN-1:0] imm_u;
    logic [XLEN-1:0] imm_j;

    logic            is_load_dec;
    logic            is_store_dec;
    logic            is_branch_dec;
    logic            is_jal_dec;
    logic            is_jalr_dec;
    logic            is_system_dec;
    logic            is_fence_dec;

    logic [XLEN-1:0] alu_res;
    logic [XLEN-1:0] wb_data;
    logic            regfile_wen;
    logic            retire_fire;

    logic            fault_now;
    logic            ecall_or_ebreak_now;

    logic            wb_is_store;
    logic            wb_is_load;
    logic [2:0]      wb_funct3;
    logic [1:0]      wb_addr_lsb;
    logic [XLEN-1:0] wb_rs2_data;

    logic [XLEN-1:0] load_ext_data;

    logic            pipe_accept;

    assign pipe_accept = (state == ST_RUN);

    assign decoded_opcode = ex_instr[6:0];
    assign funct3         = ex_instr[14:12];
    assign funct7         = ex_instr[31:25];
    assign rs1_idx        = ex_instr[19:15];
    assign rs2_idx        = ex_instr[24:20];
    assign rd_idx         = ex_instr[11:7];

    assign rs1_data       = (rs1_idx == 5'd0) ? {XLEN{1'b0}} : regfile[rs1_idx];
    assign rs2_data       = (rs2_idx == 5'd0) ? {XLEN{1'b0}} : regfile[rs2_idx];

    assign imm_i = {{20{ex_instr[31]}}, ex_instr[31:20]};
    assign imm_s = {{20{ex_instr[31]}}, ex_instr[31:25], ex_instr[11:7]};
    assign imm_b = {{19{ex_instr[31]}}, ex_instr[31], ex_instr[7], ex_instr[30:25], ex_instr[11:8], 1'b0};
    assign imm_u = {ex_instr[31:12], 12'h000};
    assign imm_j = {{11{ex_instr[31]}}, ex_instr[31], ex_instr[19:12], ex_instr[20], ex_instr[30:21], 1'b0};

    assign is_load_dec   = (decoded_opcode == OPCODE_LOAD);
    assign is_store_dec  = (decoded_opcode == OPCODE_STORE) | is_store;
    assign is_branch_dec = (decoded_opcode == OPCODE_BRANCH);
    assign is_jal_dec    = (decoded_opcode == OPCODE_JAL);
    assign is_jalr_dec   = (decoded_opcode == OPCODE_JALR) | is_jalr;
    assign is_system_dec = (decoded_opcode == OPCODE_SYSTEM);
    assign is_fence_dec  = (decoded_opcode == OPCODE_MISC) && (funct3 == 3'b000);

    always @(*) begin
        alu_res = {XLEN{1'b0}};
        case (decoded_opcode)
            7'b0110011: begin
                case (funct3)
                    3'b000: alu_res = (funct7[5]) ? (rs1_data - rs2_data) : (rs1_data + rs2_data);
                    3'b111: alu_res = rs1_data & rs2_data;
                    3'b110: alu_res = rs1_data | rs2_data;
                    3'b100: alu_res = rs1_data ^ rs2_data;
                    default: alu_res = rs1_data + rs2_data;
                endcase
            end
            7'b0010011: alu_res = rs1_data + imm_i;
            7'b0110111: alu_res = imm_u;
            7'b0010111: alu_res = ex_pc + imm_u;
            default:    alu_res = rs1_data + rs2_data;
        endcase
    end

    always @(*) begin
        next_pc = pc + INST_ALIGN;
        if (ex_valid && is_branch_dec) begin
            if (branch_taken) begin
                if (branch_imm) next_pc = ex_pc + 32'd1;
                else            next_pc = ex_pc + imm_b;
            end else begin
                next_pc = ex_pc + INST_ALIGN;
            end
        end
        if (ex_valid && is_jal_dec) begin
            next_pc = ex_pc + imm_j;
        end
        if (ex_valid && is_jalr_dec) begin
            if (imm) next_pc = ({31'b0, rs1} + 32'd1) & 32'hffff_fffe;
            else     next_pc = (rs1_data + imm_i) & 32'hffff_fffe;
        end
        if (ex_valid && (is_ecall || is_ebreak)) begin
            next_pc = ex_pc + INST_ALIGN;
        end
    end

    always @(*) begin
        ecall_or_ebreak_now = is_ecall | is_ebreak | (is_system_dec && (ex_instr[31:20] == 12'h000 || ex_instr[31:20] == 12'h001));
        fault_now = misaligned_access | illegal_shamt | ecall_or_ebreak_now;
    end

    always @(*) begin
        wb_is_store = wb_valid && ((wb_instr[6:0] == OPCODE_STORE) | is_store);
        wb_is_load  = wb_valid && (wb_instr[6:0] == OPCODE_LOAD);
        wb_funct3   = wb_instr[14:12];
        wb_addr_lsb = d_addr[1:0];
    end

    always @(*) begin
        d_be = 4'b0000;
        if (wb_is_store) begin
            case (wb_funct3)
                3'b000: begin
                    case (wb_addr_lsb)
                        2'b00: d_be = 4'b0001;
                        2'b01: d_be = 4'b0010;
                        2'b10: d_be = 4'b0100;
                        default: d_be = 4'b1000;
                    endcase
                end
                3'b001: d_be = wb_addr_lsb[1] ? 4'b1100 : 4'b0011;
                default: d_be = 4'b1111;
            endcase
        end
    end

    always @(*) begin
        load_ext_data = d_rdata;
        case (wb_funct3)
            3'b000: begin
                case (wb_addr_lsb)
                    2'b00: load_ext_data = {{24{d_rdata[7]}}, d_rdata[7:0]};
                    2'b01: load_ext_data = {{24{d_rdata[15]}}, d_rdata[15:8]};
                    2'b10: load_ext_data = {{24{d_rdata[23]}}, d_rdata[23:16]};
                    default: load_ext_data = {{24{d_rdata[31]}}, d_rdata[31:24]};
                endcase
            end
            3'b001: begin
                if (wb_addr_lsb[1]) load_ext_data = {{16{d_rdata[31]}}, d_rdata[31:16]};
                else                load_ext_data = {{16{d_rdata[15]}}, d_rdata[15:0]};
            end
            3'b100: begin
                case (wb_addr_lsb)
                    2'b00: load_ext_data = {24'h000000, d_rdata[7:0]};
                    2'b01: load_ext_data = {24'h000000, d_rdata[15:8]};
                    2'b10: load_ext_data = {24'h000000, d_rdata[23:16]};
                    default: load_ext_data = {24'h000000, d_rdata[31:24]};
                endcase
            end
            3'b101: begin
                if (wb_addr_lsb[1]) load_ext_data = {16'h0000, d_rdata[31:16]};
                else                load_ext_data = {16'h0000, d_rdata[15:0]};
            end
            default: load_ext_data = d_rdata;
        endcase
        if (load_data_ext) begin
            load_ext_data = {31'b0, d_rdata[0]};
        end
    end

    always @(*) begin
        wb_data = alu_res;
        regfile_wen = 1'b0;
        if (wb_valid && !fault_now) begin
            if (wb_is_load) begin
                wb_data = load_ext_data;
                regfile_wen = 1'b1;
            end else if ((wb_instr[6:0] == OPCODE_JAL) || (wb_instr[6:0] == OPCODE_JALR)) begin
                wb_data = wb_pc + INST_ALIGN;
                regfile_wen = 1'b1;
            end else if (!wb_is_store && (wb_instr[6:0] != OPCODE_BRANCH) && (wb_instr[6:0] != OPCODE_SYSTEM) && (wb_instr[6:0] != OPCODE_MISC)) begin
                wb_data = alu_res;
                regfile_wen = 1'b1;
            end
        end
    end

    assign retire_fire = wb_valid && !fault_now && (state == ST_RUN);

    always @(posedge clk or negedge rst_n) begin
        integer k;
        if (!rst_n) begin
            state    <= ST_RESET;
            pc       <= RESET_PC[XLEN-1:0];
            if_valid <= 1'b0;
            ex_valid <= 1'b0;
            wb_valid <= 1'b0;
            if_pc    <= {XLEN{1'b0}};
            ex_pc    <= {XLEN{1'b0}};
            wb_pc    <= {XLEN{1'b0}};
            if_instr <= {XLEN{1'b0}};
            ex_instr <= {XLEN{1'b0}};
            wb_instr <= {XLEN{1'b0}};
            wb_rs2_data <= {XLEN{1'b0}};
            d_addr   <= {XLEN{1'b0}};
            d_wdata  <= {XLEN{1'b0}};
            d_we     <= 1'b0;
            d_valid  <= 1'b0;
            i_addr   <= RESET_PC[XLEN-1:0];
            i_valid  <= 1'b0;
            excpt_o  <= 1'b0;
            for (k = 0; k < 32; k = k + 1) begin
                regfile[k] <= {XLEN{1'b0}};
            end
        end else begin
            excpt_o <= 1'b0;
            i_valid <= 1'b1;

            case (state)
                ST_RESET: begin
                    state <= ST_RUN;
                    pc    <= RESET_PC[XLEN-1:0];
                    i_addr <= RESET_PC[XLEN-1:0];
                    if_valid <= 1'b0;
                    ex_valid <= 1'b0;
                    wb_valid <= 1'b0;
                    d_valid  <= 1'b0;
                    d_we     <= 1'b0;
                end

                ST_RUN: begin
                    i_addr  <= pc;
                    if_pc   <= pc;
                    if_instr <= i_rdata;
                    if_valid <= pipe_accept;

                    ex_pc   <= if_pc;
                    ex_instr <= if_instr;
                    ex_valid <= if_valid;

                    wb_pc   <= ex_pc;
                    wb_instr <= ex_instr;
                    wb_valid <= ex_valid;
                    wb_rs2_data <= rs2_data;

                    d_addr  <= rs1_data + imm_s;
                    d_wdata <= rs2_data;
                    d_we    <= wb_valid && wb_is_store && !misaligned_access;
                    d_valid <= wb_valid && (wb_is_store || wb_is_load) && !misaligned_access;

                    if (wb_valid) begin
                        if (fault_now) begin
                            excpt_o <= 1'b1;
                        end
                        if (retire_fire && regfile_wen && (rd_idx != 5'd0)) begin
                            regfile[rd_idx] <= wb_data;
                        end
                        regfile[0] <= {XLEN{1'b0}};
                        pc <= next_pc;
                    end

                    if (ex_valid && is_fence_dec) begin
                        state   <= ST_FENCE;
                        if_valid <= 1'b0;
                        ex_valid <= 1'b0;
                        wb_valid <= 1'b0;
                        d_valid  <= 1'b0;
                        d_we     <= 1'b0;
                    end
                end

                ST_FENCE: begin
                    state   <= ST_RUN;
                    i_addr  <= pc;
                    if_valid <= 1'b0;
                    ex_valid <= 1'b0;
                    wb_valid <= 1'b0;
                    d_valid  <= 1'b0;
                    d_we     <= 1'b0;
                end

                default: begin
                    state <= ST_RESET;
                end
            endcase
        end
    end

endmodule

